def extract_keywords(text: str) -> list:
    """Pull non-stopword tokens from text, deduplicated."""
    tokens = re.findall(r"\b[a-z]{3,}\b", normalize_text(text))
    seen = set()
    keywords = []
    for t in tokens:
        if t not in STOPWORDS and t not in seen:
            seen.add(t)
            keywords.append(t)
    return keywords

